package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="resume_entry_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeEntryTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="resume_entry_id",nullable=false) private ResumeEntry entry; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String title; @Column(nullable=false) private String organization; private String location; @Column(columnDefinition="text") private String summary; }
